import { createServerSupabase } from '@/lib/supabase-server'
import { NextRequest, NextResponse } from 'next/server'

// GET /api/fichas?mesa_id=xxx  — lista fichas da mesa (mestre/admin)
// GET /api/fichas?minha=true   — ficha do jogador logado
export async function GET(req: NextRequest) {
  const supabase = await createServerSupabase()
  const { data: { user } } = await supabase.auth.getUser()
  if (!user) return NextResponse.json({ error: 'Não autorizado' }, { status: 401 })

  const { searchParams } = new URL(req.url)
  const mesaId = searchParams.get('mesa_id')
  const minha  = searchParams.get('minha')

  if (minha) {
    const { data, error } = await supabase
      .from('fichas').select('*').eq('jogador_id', user.id).single()
    if (error) return NextResponse.json({ error: error.message }, { status: 404 })
    return NextResponse.json(data)
  }

  if (mesaId) {
    const { data, error } = await supabase
      .from('fichas').select('*, perfis(nome)').eq('mesa_id', mesaId)
    if (error) return NextResponse.json({ error: error.message }, { status: 400 })
    return NextResponse.json(data)
  }

  return NextResponse.json({ error: 'Parâmetro obrigatório' }, { status: 400 })
}

// PATCH /api/fichas/:id — atualiza campos da ficha
export async function PATCH(req: NextRequest) {
  const supabase = await createServerSupabase()
  const { data: { user } } = await supabase.auth.getUser()
  if (!user) return NextResponse.json({ error: 'Não autorizado' }, { status: 401 })

  const body = await req.json()
  const { id, ...campos } = body

  if (!id) return NextResponse.json({ error: 'ID obrigatório' }, { status: 400 })

  // Busca a ficha para checar permissão de campos fixos
  const { data: ficha } = await supabase.from('fichas').select('selada, jogador_id').eq('id', id).single()
  if (!ficha) return NextResponse.json({ error: 'Ficha não encontrada' }, { status: 404 })

  // Verifica papel do usuário
  const { data: perfil } = await supabase.from('perfis').select('role').eq('id', user.id).single()
  const role = perfil?.role

  // Campos fixos protegidos
  const CAMPOS_FIXOS = ['nome','apelido','passado','faccao','atr_for','atr_agi',
    'atr_vig','atr_int','atr_pre','sangue_max','medo_max','pericias',
    'desvantagens','habilidades']

  // Se ficha selada e usuário não é mestre/admin, bloqueia campos fixos
  if (ficha.selada && role === 'jogador') {
    for (const campo of CAMPOS_FIXOS) {
      if (campo in campos) {
        return NextResponse.json(
          { error: `Campo "${campo}" está selado e não pode ser alterado.` },
          { status: 403 }
        )
      }
    }
  }

  const { data, error } = await supabase.from('fichas').update(campos).eq('id', id).select().single()
  if (error) return NextResponse.json({ error: error.message }, { status: 400 })
  return NextResponse.json(data)
}
